/**
 * @name Path traversal from agent arguments to file operations
 * @description Finds cases where agent arguments (agentArgs) flow into file system operations
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-agent-args
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module AgentArgsPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // premain/agentmain arguments
    exists(Method m, Parameter p |
      (m.hasName("premain") or m.hasName("agentmain")) and
      p = m.getAParameter() and
      p.getType().(RefType).hasQualifiedName("java.lang", "String") and
      source.asParameter() = p
    )
    or
    // String split/substring results from agent args
    exists(MethodCall mc |
      (mc.getMethod().hasName("split") or mc.getMethod().hasName("substring") or
       mc.getMethod().hasName("trim") or mc.getMethod().hasName("get")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // URL constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module AgentArgsPathFlow = TaintTracking::Global<AgentArgsPathConfig>;
import AgentArgsPathFlow::PathGraph

from AgentArgsPathFlow::PathNode source, AgentArgsPathFlow::PathNode sink
where AgentArgsPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: agent argument flows into file system operation from $@.", source.getNode(), "agent argument source"

/**
 * @name Path traversal in PlguinClassLoader - startsWith without canonicalization
 * @description The plugin class loader checks path containment using startsWith on a non-canonicalized path
 * @kind path-problem
 * @problem.severity error
 * @id java/plugin-classloader-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module PluginClassLoaderConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any string that flows into the PlguinClassLoader
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "PlguinClassLoader") and
      source.asExpr() = ce.getAnArgument()
    )
    or
    // File constructor that is passed to the classloader
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      source.asExpr() = ce
    )
    or
    // Parameters of methods in PlguinClassLoader
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "PlguinClassLoader") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // The startsWith call in PlguinClassLoader
    exists(MethodCall mc |
      mc.getMethod().hasName("startsWith") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "PlguinClassLoader") and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module PluginClassLoaderFlow = TaintTracking::Global<PluginClassLoaderConfig>;
import PluginClassLoaderFlow::PathGraph

from PluginClassLoaderFlow::PathNode source, PluginClassLoaderFlow::PathNode sink
where PluginClassLoaderFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path used in PlguinClassLoader startsWith check from $@.", source.getNode(), "source"

/**
 * @name External input to File constructor without path traversal prevention
 * @description Agent arguments or property values flow directly into File constructors in plugin manager code
 * @kind path-problem
 * @problem.severity error
 * @id java/plugin-manager-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking

module PluginManagerPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters from premain/agentmain in BootstrapAgent/AgentImpl
    exists(Method m, Parameter p |
      (m.hasName("premain") or m.hasName("agentmain")) and
      p = m.getAParameter() and
      p.getType().(RefType).hasQualifiedName("java.lang", "String") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction in PluginManagerImpl
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "PluginManagerImpl") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // File construction in OneAgentPlugin  
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "OneAgentPlugin") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // File construction in TraditionalPlugin
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.alibaba.oneagent.plugin", "TraditionalPlugin") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // Block paths through canonicalization (these would be safe)
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("getCanonicalFile") or
       mc.getMethod().hasName("toRealPath")) and
      node.asExpr() = mc
    )
  }
}

module PluginManagerPathFlow = TaintTracking::Global<PluginManagerPathConfig>;
import PluginManagerPathFlow::PathGraph

from PluginManagerPathFlow::PathNode source, PluginManagerPathFlow::PathNode sink
where PluginManagerPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Agent argument flows into File constructor in plugin code without canonicalization from $@.", source.getNode(), "agent argument"

/**
 * @name ZIP Slip vulnerability in IOUtils.unzip
 * @description ZipEntry.getName() flows into File constructor without path traversal check - classic ZIP Slip
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // ZipEntry.getName() - classic zip slip source
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // No barrier - check if there's any path validation (startsWith, contains, etc.)
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("getCanonicalFile") or
       mc.getMethod().hasName("toRealPath") or
       mc.getMethod().hasName("startsWith")) and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ZIP Slip vulnerability: ZipEntry.getName() flows into file operation without path traversal check from $@.", source.getNode(), "ZipEntry.getName()"
